public class ToegepasteTussenkomstFixerImp implements ToegepasteTussenkomstFixer {

    @Autowired
    private ManueleTussenkomstService manueleTussenkomstService;
    @Autowired
    private RekenResultatenService rekenResultatenService;
    @Autowired
    private AardKodeExtensieFacade aardKodeExtensieFacade;
    @Autowired
    private PersoonService persoonService;

    @Autowired
    private MaandTotaalService maandTotaalService;

    private static final String REKENRESULTATEN_FETCH_STRING = "rekenLijnen{toegepasteTussenkomsten}";

    private static final List<RekenBedragType> OVERNEEMBARE_BEDRAGTYPES = ImmutableList
            .of(RekenBedragType.BEDRIJFSVOORHEFFING, RekenBedragType.BEDRIJFSVOORHEFFING_ACHTERSTAL,
                    RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_A, RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_INHOUDINGEN,
                    RekenBedragType.BIJZONDERE_BIJDRAGE, RekenBedragType.VRIJSTELLING_BELASTBAAR);

    @Override
    public void fixToegepasteTussenkomsten(Admin admin, Integer persoonId, LocalDate beginDatum, Integer fiscaalJaar) {
        Month maand = new Month(beginDatum);
        TemporalContext.getInstance().setActualInterval(maand);
        Persoon persoon = persoonService.getById(admin, persoonId, "opdrachten{opdrachtSlices,opperSlices}");
        List<RekenHoofd> rekenresultaten =
                rekenResultatenService.findByPersoonIdBegindatum(admin, persoonId, beginDatum, REKENRESULTATEN_FETCH_STRING);
        TemporalContext.getInstance().clearActualInterval();

        cleanResultaten(admin, persoonId, maand, rekenresultaten);

        List<ManueleTussenkomst> tussenkomsten = vindToepasselijkeTussenkomsten(admin, persoonId, beginDatum);

        MoneyMap<OpperAkeRegimeBedragTypeKey> toegepastMap = bepaalToegepastMap(persoon, rekenresultaten);
        MoneyMap<OpperAkeRegimeBedragTypeKey> tussenkomstMap = bepaalTussenkomstMap(persoon, tussenkomsten);
        Map<OpperAkeRegimeKey, RekenLijn> rekenLijnMap = bepaalRekenLijnMap(persoon, rekenresultaten, fiscaalJaar);

        MoneyMap<OpperAkeRegimeBedragTypeKey> nieuwToegepastMap = berekenNieuweToegepasten(toegepastMap, tussenkomstMap);

        bewaarNieuweToegepasten(admin, persoon, rekenresultaten, nieuwToegepastMap, rekenLijnMap, maand, fiscaalJaar);
    }

    private ToegepasteTussenkomst maakToegepasteTussenkomst(RekenBedragType bedragType, Money bedrag) {
        ToegepasteTussenkomst toegepast = new ToegepasteTussenkomstPO();
        toegepast.setBedragType(bedragType);
        toegepast.setBedrag(bedrag);
        return toegepast;
    }

    private RekenHoofd maakRekenHoofd(RekenHoofd ander, Integer fiscaalJaar) {
        RekenHoofd rekenHoofd = new RekenHoofdPO();
        rekenHoofd.setOpdracht(ander.getOpdracht());
        rekenHoofd.setBeginDatum(ander.getBeginDatum());
        rekenHoofd.setEindDatum(ander.getEindDatum());
        rekenHoofd.setRekenTijdstip(ander.getRekenTijdstip());
        rekenHoofd.setRekenDatum(ander.getRekenDatum());
        rekenHoofd.setBeslagDatum(ander.getBeslagDatum());

        rekenHoofd.setJaar(ander.getJaar());
        rekenHoofd.setKwartaal(ander.getKwartaal());
        rekenHoofd.setFiscaalJaar(fiscaalJaar);
        rekenHoofd.setAchterstal(fiscaalJaar.compareTo(ander.getBeginDatum().getYear()) != 0);
        rekenHoofd.setRekenModus(ander.getRekenModus());

        rekenHoofd.setRekenGroep(ander.getRekenGroep());
        rekenHoofd.setHoedanigheid(ander.getHoedanigheid());
        rekenHoofd.setCategorie(ander.getCategorie());
        rekenHoofd.setWerkgeversCategorie(ander.getWerkgeversCategorie());
        rekenHoofd.setWerknemersKengetal(ander.getWerknemersKengetal());
        rekenHoofd.setPensioenStelsel(ander.getPensioenStelsel());
        rekenHoofd.setBron(RekenHoofdBron.CONVERSIE);
        rekenHoofd.setRekenLijnen(new HashSet<>());
        rekenHoofd.setRnummer(ander.getRnummer());
        maakArtikelHoofd(rekenHoofd);
        return rekenHoofd;
    }

    private ArtikelHoofd maakArtikelHoofd(RekenHoofd rekenHoofd) {
        ArtikelHoofd artikelHoofd = new ArtikelHoofdPO();
        artikelHoofd.setRekenHoofd(rekenHoofd);
        artikelHoofd.setArtikelTijdstip(rekenHoofd.getRekenTijdstip());
        artikelHoofd.setBoekDatum(rekenHoofd.getRekenDatum());
        artikelHoofd.setBoekJaar(rekenHoofd.getJaar());
        artikelHoofd.setArtikelBedragen(new HashSet<>());
        artikelHoofd.setSnummer(rekenHoofd.getRnummer());
        artikelHoofd.setArtikelBedragen(new HashSet<>());
        rekenHoofd.addArtikelHoofd(artikelHoofd);
        return artikelHoofd;
    }

    private RekenLijn maakRekenLijn(LocalDateInterval periode, LnedefRegBv regimeBv, AardKodeExtensie loonCode) {
        RekenLijn lijn = new RekenLijnPO();
        lijn.setBeginDatum(periode.getStart());
        lijn.setEindDatum(periode.getEnd());
        lijn.setAardKodeExtensie(loonCode);
        lijn.setRegimeBv(regimeBv);
        lijn.setRekenBedragen(new HashSet<>());
        lijn.setToegepasteTussenkomsten(new HashSet<>());
        lijn.setRekenInfos(new HashSet<>());
        lijn.setReferentieJaar(null);
        lijn.setTypeBoeking(AardRekenelement.SALDO);
        return lijn;
    }

    private List<ManueleTussenkomst> vindToepasselijkeTussenkomsten(Admin admin, Integer persoonid, LocalDate beginDatum) {
        Month maand = new Month(beginDatum);
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("opdracht.persoon.id", Criterium.EQ(persoonid));
        cb.and("bedragType", Criterium.IN(OVERNEEMBARE_BEDRAGTYPES));
        cb.and("datum", Criterium.GE(maand.getStart()));
        cb.and("datum", Criterium.LE(maand.getEnd()));

        return manueleTussenkomstService.findByCriteria(admin, cb);
    }

    private MoneyMap<OpperAkeRegimeBedragTypeKey> bepaalToegepastMap(Persoon persoon, List<RekenHoofd> bestaanden) {
        Map<Integer, AardKodeExtensie> akeIdToAardKodeExtensieMap = new HashMap<>();
        Map<Integer, Opdracht> idToOpdracht = AlgemeenTools.maakIdToIdentifiableMap(persoon.getOpdrachten());
        MoneyMap<OpperAkeRegimeBedragTypeKey> toegepastMap = new HashMoneyMap<>();
        for (RekenHoofd hoofd : bestaanden) {
            if (hoofd.getRnummer() != null) {
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    for (ToegepasteTussenkomst toegepast : lijn.getToegepasteTussenkomsten()) {
                        Opdracht opdracht = idToOpdracht.get(hoofd.getOpdracht().getId());
                        Opper opper = RekenTools.findOpper(opdracht, lijn.getEindDatum());
                        if (opper == null) {
                            opper = RekenTools.getOpperLaatsteGegevens(opdracht);
                        }

                        AardKodeExtensie looncode = akeIdToAardKodeExtensieMap.get(lijn.getAardKodeExtensie().getId());
                        if (looncode == null) {
                            looncode = aardKodeExtensieFacade.getById(lijn.getAardKodeExtensie().getId());
                            akeIdToAardKodeExtensieMap.put(looncode.getId(), looncode);
                        }
                        OpperAkeRegimeBedragTypeKey key =
                                new OpperAkeRegimeBedragTypeKey(opper, looncode, lijn.getRegimeBv(), toegepast.getBedragType());
                        toegepastMap.addToMoney(key, toegepast.getBedrag());
                    }
                }
            }
        }
        return toegepastMap;
    }

    private MoneyMap<OpperAkeRegimeBedragTypeKey> bepaalTussenkomstMap(Persoon persoon, List<ManueleTussenkomst> tussenkomsten) {
        Map<Integer, AardKodeExtensie> akeIdToAardKodeExtensieMap = new HashMap<>();
        Map<Integer, Opdracht> idToOpdracht = AlgemeenTools.maakIdToIdentifiableMap(persoon.getOpdrachten());
        MoneyMap<OpperAkeRegimeBedragTypeKey> tussenkomstMap = new HashMoneyMap<>();
        for (ManueleTussenkomst tussenkomst : tussenkomsten) {
            Opdracht opdracht = idToOpdracht.get(tussenkomst.getOpdracht().getId());
            Opper opper = RekenTools.findOpper(opdracht, tussenkomst.getDatum());
            if (opper == null) {
                opper = RekenTools.getOpperLaatsteGegevens(opdracht);
            }

            AardKodeExtensie looncode = akeIdToAardKodeExtensieMap.get(tussenkomst.getAardKodeExtensie().getId());
            if (looncode == null) {
                looncode = aardKodeExtensieFacade.getById(tussenkomst.getAardKodeExtensie().getId());
                akeIdToAardKodeExtensieMap.put(looncode.getId(), looncode);
            }
            OpperAkeRegimeBedragTypeKey key =
                    new OpperAkeRegimeBedragTypeKey(opper, looncode, tussenkomst.getRegimeBv(), tussenkomst.getBedragType());
            tussenkomstMap.addToMoney(key, tussenkomst.getBedrag());
        }
        return tussenkomstMap;
    }

    private Map<OpperAkeRegimeKey, RekenLijn> bepaalRekenLijnMap(Persoon persoon, List<RekenHoofd> bestaanden, Integer fiscaalJaar) {
        Map<Integer, AardKodeExtensie> akeIdToAardKodeExtensieMap = new HashMap<>();
        Map<Integer, Opdracht> idToOpdracht = AlgemeenTools.maakIdToIdentifiableMap(persoon.getOpdrachten());
        Map<OpperAkeRegimeKey, RekenLijn> rekenLijnMap = new HashMap<>();
        for (RekenHoofd hoofd : bestaanden) {
            if (hoofd.getRnummer() != null && hoofd.getFiscaalJaar().equals(fiscaalJaar)) {
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    if (lijn.getTypeBoeking() == AardRekenelement.SALDO) {
                        Opdracht opdracht = idToOpdracht.get(hoofd.getOpdracht().getId());
                        Opper opper = RekenTools.findOpper(opdracht, lijn.getEindDatum());
                        if (opper == null) {
                            opper = RekenTools.getOpperLaatsteGegevens(opdracht);
                        }

                        AardKodeExtensie looncode = akeIdToAardKodeExtensieMap.get(lijn.getAardKodeExtensie().getId());
                        if (looncode == null) {
                            looncode = aardKodeExtensieFacade.getById(lijn.getAardKodeExtensie().getId());
                            akeIdToAardKodeExtensieMap.put(looncode.getId(), looncode);
                        }
                        OpperAkeRegimeKey key = new OpperAkeRegimeKey(opper, lijn.getRegimeBv(), looncode);
                        RekenLijn found = rekenLijnMap.get(key);
                        if (found == null || hoofd.getRekenTijdstip().isAfter(found.getRekenHoofd().getRekenTijdstip())) {
                            rekenLijnMap.put(key, lijn);
                        }
                    }

                }
            }
        }
        return rekenLijnMap;
    }

    private Map<Opper, RekenHoofd> bepaalRekenHoofdMap(Persoon persoon, List<RekenHoofd> bestaanden, Integer fiscaalJaar) {
        Map<Integer, Opdracht> idToOpdracht = AlgemeenTools.maakIdToIdentifiableMap(persoon.getOpdrachten());
        Map<Opper, RekenHoofd> rekenHoofdMap = new HashMap<>();
        for (RekenHoofd hoofd : bestaanden) {
            if (hoofd.getRnummer() != null) {
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    if (lijn.getTypeBoeking() == AardRekenelement.SALDO) {
                        Opdracht opdracht = idToOpdracht.get(hoofd.getOpdracht().getId());
                        Opper opper = RekenTools.findOpper(opdracht, lijn.getEindDatum());
                        if (opper == null) {
                            opper = RekenTools.getOpperLaatsteGegevens(opdracht);
                        }

                        RekenHoofd found = rekenHoofdMap.get(opper);
                        if (found == null || hoofd.getRekenTijdstip().isAfter(found.getRekenTijdstip())) {
                            RekenHoofd rekenHoofd = maakRekenHoofd(hoofd, fiscaalJaar);
                            rekenHoofdMap.put(opper, rekenHoofd);
                        }
                    }
                }
            }
        }
        return rekenHoofdMap;
    }

    private MoneyMap<OpperAkeRegimeBedragTypeKey> berekenNieuweToegepasten(
            MoneyMap<OpperAkeRegimeBedragTypeKey> toegepastMap,
            MoneyMap<OpperAkeRegimeBedragTypeKey> tussenkomstMap) {
        MoneyMap<OpperAkeRegimeBedragTypeKey> nieuwToegepastMap = new HashMoneyMap<>();

        Set<OpperAkeRegimeBedragTypeKey> keySet = new HashSet<>(toegepastMap.keySet());
        keySet.addAll(tussenkomstMap.keySet());
        for (OpperAkeRegimeBedragTypeKey key : keySet) {
            Money toegepastBedrag = toegepastMap.getMoney(key);
            Money tussenkomstBedrag = tussenkomstMap.getMoney(key);

            Money nieuwBedrag = tussenkomstBedrag.subtract(toegepastBedrag);
            if (nieuwBedrag.signum() != 0) {
                nieuwToegepastMap.addToMoney(key, nieuwBedrag);
            }
        }
        return nieuwToegepastMap;
    }

    private void bewaarNieuweToegepasten(
            Admin admin, Persoon persoon, List<RekenHoofd> rekenresultaten,
            MoneyMap<OpperAkeRegimeBedragTypeKey> nieuwToegepastMap, Map<OpperAkeRegimeKey, RekenLijn> rekenLijnMap, Month maand, Integer fiscaalJaar) {
        Map<Opper, RekenHoofd> nieuweRekenHoofden = bepaalRekenHoofdMap(persoon, rekenresultaten, fiscaalJaar);
        List<ToegepasteTussenkomst> toBeCreated = new ArrayList<>();
        for (OpperAkeRegimeBedragTypeKey key : nieuwToegepastMap.keySet()) {
            OpperAkeRegimeKey opperAkeRegimeKey = new OpperAkeRegimeKey(key.getOpper(), key.getRegimeBv(), key.getAardKodeExtensie());
            RekenLijn lijn = rekenLijnMap.get(opperAkeRegimeKey);
            ToegepasteTussenkomst toegepasteTussenkomst = maakToegepasteTussenkomst(key.getRekenBedragType(), nieuwToegepastMap.getMoney(key));
            if (lijn != null) {
                toegepasteTussenkomst.setRekenLijn(lijn);
                if (lijn.getId() != null) {
                    toBeCreated.add(toegepasteTussenkomst);
                }
            } else {
                RekenHoofd rekenHoofd = nieuweRekenHoofden.get(key.getOpper());
                if (rekenHoofd != null) {
                    LocalDateInterval periode = key.getOpper().getActualInterval().overlap(maand);
                    RekenLijn rekenLijn = maakRekenLijn(periode, key.getRegimeBv(), key.getAardKodeExtensie());
                    toegepasteTussenkomst.setRekenLijn(lijn);
                    rekenLijn.getToegepasteTussenkomsten().add(toegepasteTussenkomst);
                    rekenLijnMap.put(opperAkeRegimeKey, rekenLijn);
                    rekenHoofd.addRekenLijn(rekenLijn);
                }
            }
        }
        rekenResultatenService.createToegepasteTussenkomsten(admin, toBeCreated);
        rekenResultatenService.create(admin, nieuweRekenHoofden.values());
    }

    public void cleanResultaten(Admin admin, Integer persoonId, LocalDateInterval rekenPeriode, List<RekenHoofd> bestaanden) {
        TimeLogContext.getInstance().startTimeLogging("ToegepasteTussenkomstFixer.cleanResultaten");

        for (RekenHoofd hoofd : bestaanden) {
            if (hoofd.getRnummer() == null) {
                TimeLogContext.getInstance().startTimeLogging("RekenMotorService.rekenResultatenService.delete");
                rekenResultatenService.delete(admin, hoofd);
                TimeLogContext.getInstance().endTimeLogging();
            }
        }
        TimeLogContext.getInstance().startTimeLogging("MaandtotaalResultaatHandlerImp.maandTotaalService.delete");
        maandTotaalService.deleteZonderSnummer(admin, new PersoonPO(persoonId), rekenPeriode);
        TimeLogContext.getInstance().endTimeLogging();
    }

}
